import { MeshEngine, type Task, type AsyncForkResult, type AsyncRaceResult, type AsyncFoldResult } from './mesh-engine';
import { FORK, VOID, type MeshVertex } from './scheduling-mesh';
import { createRegister, type QuantumRegister } from './quantum';

/**
 * Caps topological fabric expansion for one scheduling request so a single burst
 * cannot exhaust the global safety bound. Tune from expected dark-queue depth:
 * each successful dark tick typically drains a small batch (e.g. 4 chunks in matvec bench).
 */
export function safeFabricDimensionBudgetForDarkChunks(
  darkChunkCount: number,
  batchSize: number = 4
): number {
  const d = Math.max(0, Math.floor(darkChunkCount));
  const ticksNeeded = Math.ceil(d / Math.max(1, batchSize));
  const slack = 96;
  return Math.min(8192, slack + ticksNeeded * 3);
}

export interface DarkMatterTaskResult<T> {
  intrinsicCharge: T;
  gaugeObservationCoupling: 0; // The crucial formal constraint
  bizarroTransformation: true; // Perfect failure (Race) == Perfect success (Fold)
}

/**
 * Computational mapped equivalent for THM-DARK-FORK-HYPOTHESIS-ENERGY.
 *
 * Implements an unbounded, non-halting Fork primitive that continuously
 * radiates parallel execution branches. Since the classical scheduling mesh is finite
 * in memory, it pushes beyond those limits into the quantum fabric (Hilbert space),
 * expanding dimensions continuously so classical exhaustion limits are never reached.
 */
export class UnboundedDarkEnergyFork {
  private engine: MeshEngine;
  private running: boolean = false;
  private expansionRateDelayMs: number;
  private maxFabricDimensions: number;
  private fabricDimensionExpansion: number = 0;
  private activeFabricRegisters: QuantumRegister[] = [];

  constructor(engine: MeshEngine, expansionRateDelayMs: number = 10, maxFabricDimensions: number = 4096) {
    this.engine = engine;
    this.expansionRateDelayMs = expansionRateDelayMs;
    this.maxFabricDimensions = maxFabricDimensions;
  }

  /**
   * Starts the unbounded radiation.
   */
  start<T>(task: Task<T>): void {
    if (this.running) return;
    this.running = true;
    void this.radiate(task);
  }

  stop(): void {
    this.running = false;
  }

  isRunning(): boolean {
    return this.running;
  }

  private async radiate<T>(task: Task<T>): Promise<void> {
    while (this.running) {
      // Find idle hubs to radiate outward
      const idleHubs = this.engine.mesh.idleHubs();
      if (idleHubs.length > 0) {
        // Run normally on classical mesh
        const hubId = idleHubs[Math.floor(Math.random() * idleHubs.length)];
        if (hubId === undefined) {
          continue;
        }
        const forked = this.engine.fork(hubId, task);
        this.engine.fold(forked).catch(() => {});
      } else {
        // The classical SchedulingMesh reached its bounds.
        // We transcend into the quantum fabric to preserve unbounded expansion properties.
        if (this.fabricDimensionExpansion >= this.maxFabricDimensions) {
          // Safety bound reached to prevent catastrophic recursion memory failure
          // Simulates a cosmic particle horizon or local simulation buffer limit.
          console.warn(`[SAFETY] Dark Energy expansion hit the maximum topological fabric limit of ${this.maxFabricDimensions} dimensions. Expansion safely paused.`);
          this.running = false;
          break;
        }

        this.fabricDimensionExpansion++;

        // Allocate a new multi-dimensional register block (limitlessly scalable since it's just state vector amplitudes)
        const block = createRegister(1); // Incrementing local dimensionality
        this.activeFabricRegisters.push(block);

        // Fabric must still execute overflow work: fork() never runs when no idle hubs exist.
        const verts = this.engine.mesh.vertices;
        if (verts.length > 0) {
          const fabricSignal = new AbortController();
          const v = verts[0] as MeshVertex;
          await task(v, fabricSignal.signal).catch(() => {});
        }
      }

      // Simulate specific expansion rate
      await new Promise(r => setTimeout(r, this.expansionRateDelayMs));
    }
  }
}

/**
 * Computational mapped equivalent for THM-DARK-FORK-HYPOTHESIS-MATTER.
 *
 * Implements dark matter as disjoint Fork threads that possess intrinsic charge 
 * (they run computationally) but have a zero observational coupling for gauge forces (Race).
 */
export class DisjointDarkMatterFork {
  private engine: MeshEngine;

  constructor(engine: MeshEngine) {
    this.engine = engine;
  }

  /**
   * Spawns a disjoint fork cluster.
   * Tasks are executed on standard mesh vertices but wrapped with the dark matter trait.
   */
  forkMatter<T>(hubId: number, task: Task<T>): AsyncForkResult<DarkMatterTaskResult<T> | T> {
    // We wrap the task to enforce the gauge decoupling structurally via Bizarro transformation.
    const darkMatterWrappedTask: Task<DarkMatterTaskResult<T> | T> = async (
      vertex: MeshVertex,
      signal: AbortSignal
    ) => {
      const chargeResult = await task(vertex, signal);
      return {
        intrinsicCharge: chargeResult,
        gaugeObservationCoupling: 0,
        bizarroTransformation: true, // Tag as Bizarro inversion
      } as DarkMatterTaskResult<T>;
    };

    return this.engine.fork(hubId, darkMatterWrappedTask);
  }

  /**
   * Gauge Observation (Electromagnetism/Race)
   * A race function that functionally enforces `gaugeObservationCoupling = 0`.
   * Any promise returning a DarkMatterTaskResult is mathematically stripped from the race,
   * meaning Dark Matter is "invisible" to our standard observer threads.
   */
  async gaugeRace<T>(mixedForks: AsyncForkResult<DarkMatterTaskResult<T> | T>): Promise<AsyncRaceResult<T> | null> {
    const validPromises = mixedForks.promises.map(
      async ({
        vertexId,
        promise,
      }: {
        vertexId: number;
        promise: Promise<DarkMatterTaskResult<T> | T>;
      }) => {
      const result = await promise;
      // Filter out dark matter decoupling
      if (result && typeof result === 'object' && 'gaugeObservationCoupling' in result && result.gaugeObservationCoupling === 0) {
        // It's a dark matter thread. It does not resolve this promise.
        // We throw an internal decoupling exception, causing Promise.any/race to ignore it.
        throw new Error(`Gauge Observation Decoupled: Structural Dark Matter encountered at vertex ${vertexId}`);
      }
      return { vertexId, result: result as T };
    });

    try {
      // Use any instead of race because we reject decoupled elements
      const winner = await Promise.any(validPromises);
      mixedForks.abort.abort();
      
      return {
        winner: winner.vertexId,
        result: winner.result,
        elapsed: 0, // Simplified for this layer
        losers: [],
      };
    } catch (e) {
      if (e instanceof AggregateError) {
         // All forks were disjoint dark matter (or failed)
         return null;
      }
      throw e;
    }
  }

  /**
   * Gravity Fold
   * Fold intrinsically accesses all mass/energy regardless of gauge coupling.
   * The dark matter threads manifest structurally in the Fold resolution.
   */
  async gravityFold<T>(mixedForks: AsyncForkResult<DarkMatterTaskResult<T> | T>): Promise<AsyncFoldResult<DarkMatterTaskResult<T> | T>> {
    // The base engine fold naturally aggregates all settled nodes. Dark matter is visible.
    return this.engine.fold(mixedForks);
  }
}
